52: // ConfigKey describe a specific config item.
53: // In most cases, the name is the config's name. However, for ServiceEntry it is service's FQDN.
54: type ConfigKey struct {
55: 	Kind      config.GroupVersionKind
56: 	Name      string
57: 	Namespace string
58: }
59: 
60: func (key ConfigKey) HashCode() uint64 {
61: 	hash := md5.New()
62: 	for _, v := range []string{
63: 		key.Name,
64: 		key.Namespace,
65: 		key.Kind.Kind,
66: 		key.Kind.Group,
67: 		key.Kind.Version,
68: 	} {
69: 		hash.Write([]byte(v))
70: 	}
71: 	var tmp [md5.Size]byte
72: 	sum := hash.Sum(tmp[:0])
73: 	return binary.BigEndian.Uint64(sum)
74: }
75: 
76: func (key ConfigKey) String() string {
77: 	return key.Kind.Kind + "/" + key.Namespace + "/" + key.Name
78: }
