{"content":"862: // initRegistryEventHandlers sets up event handlers for config and service updates
863: func (s *Server) initRegistryEventHandlers() {
864: 	log.Info("initializing registry event handlers")
865: 	// Flush cached discovery responses whenever services configuration change.
866: 	serviceHandler := func(svc *model.Service, _ model.Event) {
867: 		pushReq := &model.PushRequest{
868: 			Full: true,
869: 			ConfigsUpdated: map[model.ConfigKey]struct{}{{
870: 				Kind:      gvk.ServiceEntry,
871: 				Name:      string(svc.Hostname),
872: 				Namespace: svc.Attributes.Namespace,
873: 			}: {}},
874: 			Reason: []model.TriggerReason{model.ServiceUpdate},
875: 		}
876: 		s.XDSServer.ConfigUpdate(pushReq)
877: 	}
878: 	s.ServiceController().AppendServiceHandler(serviceHandler)
879: 
880: 	if s.configController != nil {
881: 		configHandler := func(prev config.Config, curr config.Config, event model.Event) {
882: 			defer func() {
883: 				if event != model.EventDelete {
884: 					s.statusReporter.AddInProgressResource(curr)
885: 				} else {
886: 					s.statusReporter.DeleteInProgressResource(curr)
887: 				}
888: 			}()
889: 			// For update events, trigger push only if spec has changed.
890: 			if event == model.EventUpdate && !needsPush(prev, curr) {
891: 				log.Debugf("skipping push for %s as spec has not changed", prev.Key())
892: 				return
893: 			}
894: 			pushReq := &model.PushRequest{
895: 				Full: true,
896: 				ConfigsUpdated: map[model.ConfigKey]struct{}{{
897: 					Kind:      curr.GroupVersionKind,
898: 					Name:      curr.Name,
899: 					Namespace: curr.Namespace,
900: 				}: {}},
901: 				Reason: []model.TriggerReason{model.ConfigUpdate},
902: 			}
903: 			s.XDSServer.ConfigUpdate(pushReq)
904: 		}
905: 		schemas := collections.Pilot.All()
906: 		if features.EnableGatewayAPI {
907: 			schemas = collections.PilotGatewayAPI.All()
908: 		}
909: 		for _, schema := range schemas {
910: 			// This resource type was handled in external/servicediscovery.go, no need to rehandle here.
911: 			if schema.Resource().GroupVersionKind() == collections.IstioNetworkingV1Alpha3Serviceentries.
912: 				Resource().GroupVersionKind() {
913: 				continue
914: 			}
915: 			if schema.Resource().GroupVersionKind() == collections.IstioNetworkingV1Alpha3Workloadentries.
916: 				Resource().GroupVersionKind() {
917: 				continue
918: 			}
919: 			if schema.Resource().GroupVersionKind() == collections.IstioNetworkingV1Alpha3Workloadgroups.
920: 				Resource().GroupVersionKind() {
921: 				continue
922: 			}
923: 
924: 			s.configController.RegisterEventHandler(schema.Resource().GroupVersionKind(), configHandler)
925: 		}
926: 		if s.environment.GatewayAPIController != nil {
927: 			s.environment.GatewayAPIController.RegisterEventHandler(gvk.Namespace, func(config.Config, config.Config, model.Event) {
928: 				s.XDSServer.ConfigUpdate(&model.PushRequest{
929: 					Full:   true,
930: 					Reason: []model.TriggerReason{model.NamespaceUpdate},
931: 				})
932: 			})
933: 		}
934: 	}
935: }
